    # Enumerate failure modes for the GET /api/v1/problems listing contract

    failure_modes = [
        {
            "id": 1,
            "name": "Incorrect Filtering by Difficulty",
            "rationale": (
                "If the filtering logic does not correctly apply the difficulty criteria, "
                "the API may return problems outside the requested difficulty range, "
                "leading to incorrect UI displays and poor user experience."
            )
        },
        {
            "id": 2,
            "name": "Paging Limit Not Enforced or Incorrectly Applied",
            "rationale": (
                "Failing to respect the 50-result paging limit can cause the API to return "
                "too many results, which may degrade performance and break UI assumptions."
            )
        },
        {
            "id": 3,
            "name": "Non-Deterministic Ordering by roundId",
            "rationale": (
                "If the problems are not sorted deterministically by roundId, the UI may "
                "show inconsistent problem lists across requests, confusing users."
            )
        },
        {
            "id": 4,
            "name": "Missing or Incorrect Metadata Fields",
            "rationale": (
                "If metadata such as totalProblems, filteredCount, appliedLimit, or "
                "difficultyBreakdown is missing or incorrect, the UI cannot properly "
                "display summary information or pagination controls."
            )
        },
        {
            "id": 5,
            "name": "componentLanguages Not Sorted or Missing When includeComponents=true",
            "rationale": (
                "If componentLanguages are not sorted or omitted when includeComponents=true, "
                "the UI cannot reliably surface language options, degrading user experience."
            )
        }
    ]

    return failure_modes
